export interface InterviewQuestion {
  question: string;
  answer: string;
}

export const SKILL_QUESTIONS: Record<string, InterviewQuestion[]> = {
  html: [
    { question: "What is the difference between semantic and non-semantic HTML elements?", answer: "Semantic elements (header, nav, article, section) clearly describe their meaning to both the browser and developer. Non-semantic elements (div, span) tell nothing about their content. Semantic HTML improves accessibility, SEO, and code readability." },
    { question: "What is the purpose of the DOCTYPE declaration?", answer: "DOCTYPE tells the browser which version of HTML the page is written in. In HTML5, <!DOCTYPE html> ensures the browser renders in standards mode rather than quirks mode." },
    { question: "Explain the difference between <script>, <script async>, and <script defer>.", answer: "<script> blocks HTML parsing until the script is downloaded and executed. <script async> downloads in parallel and executes immediately when ready (may run out of order). <script defer> downloads in parallel but executes after HTML parsing is complete, in order." },
    { question: "What are Web Accessibility (a11y) best practices in HTML?", answer: "Use semantic elements, add alt text to images, use proper heading hierarchy, add ARIA labels where needed, ensure keyboard navigation with tabindex, use label elements with form inputs, and maintain proper color contrast." },
    { question: "What is the difference between localStorage and sessionStorage?", answer: "localStorage persists data with no expiration until explicitly cleared. sessionStorage data is cleared when the browser tab is closed. Both store key-value pairs as strings with a ~5MB limit per origin." },
    { question: "Explain the difference between block, inline, and inline-block elements.", answer: "Block elements (div, p, h1) take full width and start on new lines. Inline elements (span, a, strong) only take as much width as needed and don't start new lines. Inline-block elements behave like inline but accept width/height properties." },
  ],
  css: [
    { question: "Explain the CSS Box Model.", answer: "Every element is a rectangular box with: content (the actual content), padding (space between content and border), border (the edge), and margin (space outside the border). box-sizing: border-box includes padding and border in the element's total width/height." },
    { question: "What is the difference between Flexbox and CSS Grid?", answer: "Flexbox is one-dimensional (row OR column) and great for distributing space along a single axis. Grid is two-dimensional (rows AND columns) and ideal for complex page layouts. Use Flexbox for component-level layouts and Grid for page-level layouts." },
    { question: "How does CSS specificity work?", answer: "Specificity determines which CSS rule applies when multiple rules target the same element. The hierarchy is: inline styles (1000) > IDs (100) > classes/attributes/pseudo-classes (10) > elements/pseudo-elements (1). !important overrides all but should be avoided." },
    { question: "What is the difference between em and rem units?", answer: "em is relative to the font-size of the parent element — it compounds with nesting. rem is relative to the root element's font-size (html) — it's consistent regardless of nesting. rem is preferred for predictable sizing." },
    { question: "Explain CSS position values.", answer: "static: default flow. relative: offset from normal position, keeps space. absolute: positioned relative to nearest positioned ancestor, removed from flow. fixed: positioned relative to viewport, stays on scroll. sticky: toggles between relative and fixed based on scroll position." },
    { question: "What are CSS custom properties (variables)?", answer: "CSS variables are defined with -- prefix (e.g., --color-primary: #333) and accessed with var(). They cascade and inherit, can be scoped to selectors, and enable dynamic theming. They're defined on :root for global access." },
  ],
  javascript: [
    { question: "What is the difference between var, let, and const?", answer: "var is function-scoped, hoisted, and can be re-declared. let is block-scoped, hoisted but not initialized (temporal dead zone), can be reassigned. const is block-scoped, must be initialized at declaration, and cannot be reassigned (but object properties can be modified)." },
    { question: "Explain closures in JavaScript.", answer: "A closure is a function that retains access to its outer (lexical) scope variables even after the outer function has returned. This enables data privacy, factory functions, and callbacks that remember their context." },
    { question: "What is the event loop in JavaScript?", answer: "The event loop continuously checks if the call stack is empty, then moves callbacks from the task queue (macrotasks like setTimeout) or microtask queue (Promises) to the call stack. Microtasks have priority over macrotasks. This enables non-blocking async behavior in single-threaded JS." },
    { question: "What is the difference between == and ===?", answer: "== (loose equality) performs type coercion before comparing — '5' == 5 is true. === (strict equality) compares both value AND type without coercion — '5' === 5 is false. Always prefer === to avoid unexpected coercion bugs." },
    { question: "Explain Promises and async/await.", answer: "Promises represent eventual completion/failure of async operations with .then()/.catch(). async/await is syntactic sugar over Promises — async marks a function as returning a Promise, await pauses execution until the Promise resolves. Both handle asynchronous code; async/await provides cleaner, more readable syntax." },
    { question: "What is prototypal inheritance?", answer: "JavaScript uses prototypal inheritance where objects can inherit directly from other objects via the prototype chain. When a property isn't found on an object, JS looks up the prototype chain. Classes in JS are syntactic sugar over this prototype-based system." },
    { question: "What is the difference between map, filter, and reduce?", answer: "map transforms each element and returns a new array of same length. filter returns a new array with elements that pass a test (truthy callback). reduce accumulates array values into a single result using an accumulator and current value." },
  ],
  typescript: [
    { question: "What is the difference between interface and type in TypeScript?", answer: "Both define object shapes, but interfaces support declaration merging (can be extended by re-declaring) and are better for public APIs. Types support unions, intersections, and mapped types. Interfaces use 'extends', types use '&'. For objects, they're mostly interchangeable; for complex types (unions, tuples), use type." },
    { question: "Explain generics in TypeScript.", answer: "Generics allow creating reusable components that work with multiple types while maintaining type safety. E.g., function identity<T>(arg: T): T returns the same type passed in. They enable type-safe collections, API responses, and utility functions without using 'any'." },
    { question: "What are utility types? Name some common ones.", answer: "Utility types transform existing types. Common ones: Partial<T> makes all props optional, Required<T> makes all required, Readonly<T> makes immutable, Pick<T,K> selects specific props, Omit<T,K> removes props, Record<K,V> creates a type with keys K and values V." },
    { question: "What is a discriminated union?", answer: "A discriminated union is a pattern where union members share a common literal property (discriminant) that TypeScript uses for narrowing. E.g., type Shape = { kind: 'circle'; radius: number } | { kind: 'square'; side: number }. Switching on 'kind' narrows the type." },
    { question: "What is the 'never' type in TypeScript?", answer: "never represents values that never occur — functions that always throw, infinite loops, or exhaustive switch cases. It's the bottom type: assignable to everything but nothing is assignable to it. Useful for exhaustiveness checking in switch statements." },
  ],
  react: [
    { question: "What is the Virtual DOM and how does it work?", answer: "The Virtual DOM is a lightweight JavaScript representation of the real DOM. When state changes, React creates a new virtual DOM tree, diffs it with the previous one (reconciliation), and only updates the actual DOM nodes that changed. This batched update approach is more efficient than direct DOM manipulation." },
    { question: "Explain the useEffect hook and its dependency array.", answer: "useEffect runs side effects after render. Empty dependency array [] runs once on mount. Specific dependencies [a, b] re-run when a or b change. No array runs after every render. The cleanup function (returned function) runs before the next effect and on unmount." },
    { question: "What is the difference between controlled and uncontrolled components?", answer: "Controlled components have their value managed by React state via onChange — React is the single source of truth. Uncontrolled components store their own state internally and use refs to read values. Controlled is preferred as it gives you more control over form behavior." },
    { question: "When would you use useMemo and useCallback?", answer: "useMemo memoizes a computed value — use when an expensive calculation runs on every render. useCallback memoizes a function reference — use when passing callbacks to optimized child components (React.memo). Don't overuse them; only optimize when there's a measurable performance issue." },
    { question: "What are React keys and why are they important?", answer: "Keys help React identify which items in a list have changed, been added, or removed. They should be stable, unique identifiers (not array indices). Proper keys enable efficient re-rendering by allowing React to reuse existing DOM elements rather than recreating them." },
    { question: "Explain React Context API vs prop drilling.", answer: "Prop drilling passes data through many component layers that don't use it. Context API provides a way to share values across the component tree without explicit prop passing. Create context with createContext, provide with Provider, consume with useContext. Use for global state like themes, auth, locale." },
  ],
  "node.js": [
    { question: "What is the Node.js event loop?", answer: "Node.js uses a single-threaded event loop that handles I/O operations asynchronously via callbacks/promises. The event loop has phases: timers, I/O callbacks, idle/prepare, poll (new I/O events), check (setImmediate), and close callbacks. This enables handling thousands of concurrent connections without threads." },
    { question: "What is middleware in Express.js?", answer: "Middleware functions have access to req, res, and next. They can execute code, modify request/response, end the request cycle, or call next() to pass control. Types: application-level (app.use), router-level, error-handling (4 args), built-in (express.json), and third-party (cors, helmet)." },
    { question: "Explain the difference between CommonJS and ES Modules.", answer: "CommonJS uses require()/module.exports, is synchronous, loads at runtime, and is Node's original module system. ES Modules use import/export, are asynchronous, statically analyzed at compile time, and support tree-shaking. Use ES Modules (type: module in package.json) for modern Node.js." },
    { question: "How does Node.js handle errors in async code?", answer: "Callbacks use error-first pattern (err, data). Promises use .catch() or try/catch with async/await. Unhandled rejections crash the process in newer Node versions. Express uses error-handling middleware (err, req, res, next). Always handle errors to prevent crashes." },
    { question: "What is the difference between process.nextTick() and setImmediate()?", answer: "process.nextTick() fires before any I/O events in the current iteration of the event loop. setImmediate() fires in the check phase of the next event loop iteration. nextTick has higher priority and can starve I/O if used recursively." },
  ],
  node: [
    { question: "What is the Node.js event loop?", answer: "Node.js uses a single-threaded event loop that handles I/O operations asynchronously via callbacks/promises. The event loop has phases: timers, I/O callbacks, idle/prepare, poll, check, and close callbacks. This enables handling thousands of concurrent connections." },
    { question: "What is middleware in Express.js?", answer: "Middleware functions have access to req, res, and next. They can execute code, modify request/response, end the request cycle, or call next(). Types include application-level, router-level, error-handling, built-in, and third-party middleware." },
    { question: "Explain streams in Node.js.", answer: "Streams handle data in chunks rather than loading everything into memory. Four types: Readable (fs.createReadStream), Writable (fs.createWriteStream), Duplex (sockets), and Transform (zlib). They're memory efficient for large files and enable piping data between sources." },
  ],
  sql: [
    { question: "What is the difference between WHERE and HAVING?", answer: "WHERE filters rows before grouping (works on individual rows). HAVING filters after GROUP BY (works on aggregated results). WHERE can't use aggregate functions; HAVING can. Example: HAVING COUNT(*) > 5 vs WHERE status = 'active'." },
    { question: "Explain different types of JOINs.", answer: "INNER JOIN returns matching rows from both tables. LEFT JOIN returns all rows from left table + matching from right (NULL if no match). RIGHT JOIN is the opposite. FULL OUTER JOIN returns all rows from both (NULL where no match). CROSS JOIN returns cartesian product." },
    { question: "What are indexes and when should you use them?", answer: "Indexes are data structures (usually B-trees) that speed up data retrieval at the cost of slower writes and extra storage. Use on columns in WHERE, JOIN, and ORDER BY clauses. Don't over-index — each index slows INSERT/UPDATE. Use composite indexes for multi-column queries." },
    { question: "Explain database normalization.", answer: "Normalization reduces data redundancy. 1NF: atomic values, no repeating groups. 2NF: 1NF + no partial dependencies on composite keys. 3NF: 2NF + no transitive dependencies. BCNF: every determinant is a candidate key. Denormalization may be used for read performance." },
    { question: "What is a transaction and what are ACID properties?", answer: "A transaction is a unit of work that either fully completes or fully rolls back. ACID: Atomicity (all or nothing), Consistency (valid state to valid state), Isolation (concurrent transactions don't interfere), Durability (committed data survives crashes)." },
  ],
  git: [
    { question: "What is the difference between git merge and git rebase?", answer: "Merge creates a merge commit preserving branch history — non-destructive but creates a complex history. Rebase replays commits on top of the target branch — creates a linear history but rewrites commit hashes. Never rebase public/shared branches." },
    { question: "How do you resolve a merge conflict?", answer: "Git marks conflicts with <<<<<<, =======, >>>>>> markers. Open the file, decide which changes to keep, remove the markers, then git add and git commit. Use git mergetool for a visual diff. Communicate with team members whose changes conflict." },
    { question: "What is git stash and when would you use it?", answer: "git stash temporarily saves uncommitted changes and reverts to a clean working directory. Use when you need to switch branches but aren't ready to commit. git stash pop restores changes, git stash list shows stashed items, git stash drop removes a stash." },
  ],
  python: [
    { question: "What is the difference between a list and a tuple?", answer: "Lists are mutable (can be modified after creation), use square brackets [], and are slightly slower. Tuples are immutable, use parentheses (), are faster, and can be used as dictionary keys. Use tuples for fixed collections, lists for dynamic ones." },
    { question: "Explain Python decorators.", answer: "Decorators are functions that modify the behavior of another function without changing its code. They use @decorator syntax. They take a function as input, add functionality (logging, timing, auth), and return a modified function. Common examples: @property, @staticmethod, @app.route." },
    { question: "What are *args and **kwargs?", answer: "*args allows a function to accept any number of positional arguments as a tuple. **kwargs accepts any number of keyword arguments as a dictionary. Together they make functions flexible: def func(*args, **kwargs). They're commonly used in decorators and wrapper functions." },
    { question: "Explain Python's GIL (Global Interpreter Lock).", answer: "The GIL is a mutex that allows only one thread to execute Python bytecode at a time, even on multi-core CPUs. This limits true parallelism for CPU-bound tasks. Workarounds: use multiprocessing for CPU-bound tasks, threading for I/O-bound tasks, or async/await for concurrent I/O." },
  ],
  docker: [
    { question: "What is the difference between a Docker image and a container?", answer: "An image is a read-only template with application code, runtime, libraries, and dependencies — like a class. A container is a running instance of an image — like an object. Multiple containers can be created from one image, each with its own writable layer." },
    { question: "What is a multi-stage build?", answer: "Multi-stage builds use multiple FROM statements in a Dockerfile. Earlier stages compile/build the application, later stages copy only the artifacts needed. This produces smaller final images by excluding build tools, source code, and dev dependencies." },
    { question: "Explain Docker volumes vs bind mounts.", answer: "Volumes are managed by Docker, stored in Docker's area, and are the preferred mechanism for persistent data. Bind mounts map a host directory directly into the container. Volumes are better for production (portable, backup-friendly); bind mounts are useful for development (live code reloading)." },
  ],
  "machine learning": [
    { question: "What is the bias-variance tradeoff?", answer: "Bias is error from simplistic assumptions (underfitting). Variance is error from sensitivity to training data (overfitting). High bias = poor training performance. High variance = poor generalization. The goal is to find the sweet spot that minimizes total error on unseen data." },
    { question: "Explain cross-validation.", answer: "Cross-validation splits data into k folds, trains on k-1 folds and validates on the remaining one, rotating through all folds. K-fold CV gives a more reliable estimate of model performance than a single train/test split. Common choice is k=5 or k=10." },
    { question: "What is the difference between precision and recall?", answer: "Precision = TP/(TP+FP) — of all predicted positives, how many are actually positive (quality). Recall = TP/(TP+FN) — of all actual positives, how many did we catch (completeness). F1 score is the harmonic mean. Choose based on use case: spam filter needs high precision, disease detection needs high recall." },
  ],
  testing: [
    { question: "What is the difference between unit, integration, and E2E tests?", answer: "Unit tests test individual functions/components in isolation with mocked dependencies. Integration tests test how modules work together. E2E tests simulate real user scenarios through the entire application. The testing pyramid suggests many unit tests, fewer integration, and even fewer E2E tests." },
    { question: "What is mocking and when should you use it?", answer: "Mocking replaces real dependencies with controlled substitutes. Use mocks for: external APIs, databases, timers, random values, and any slow/unpredictable dependency. Mock at boundaries, not implementation details. Over-mocking makes tests brittle and less useful." },
  ],
  security: [
    { question: "What is XSS and how do you prevent it?", answer: "Cross-Site Scripting (XSS) injects malicious scripts into web pages viewed by other users. Prevention: sanitize/escape user input before rendering, use Content-Security-Policy headers, use httpOnly cookies, avoid innerHTML, and use frameworks that auto-escape output (React, Angular)." },
    { question: "Explain the difference between authentication and authorization.", answer: "Authentication verifies WHO you are (login, credentials, identity). Authorization determines WHAT you can do (permissions, roles, access control). Authentication comes first, then authorization. Example: logging in is authentication; checking if you can delete a post is authorization." },
    { question: "What is CSRF and how do you prevent it?", answer: "Cross-Site Request Forgery tricks users into performing unwanted actions on sites where they're authenticated. Prevention: CSRF tokens (unique per session/request), SameSite cookie attribute, checking Origin/Referer headers, and requiring re-authentication for sensitive actions." },
  ],
  "data structures": [
    { question: "What is the time complexity of operations on a hash table?", answer: "Average case: O(1) for insert, delete, and lookup. Worst case: O(n) when all keys hash to the same bucket (collision). Good hash functions and proper load factor management (resizing) keep operations near O(1)." },
    { question: "When would you use a stack vs a queue?", answer: "Stack (LIFO): undo operations, function call stack, expression evaluation, backtracking algorithms, browser history. Queue (FIFO): task scheduling, BFS traversal, message queues, print queue, handling requests in order." },
    { question: "Explain the difference between a Binary Tree and a Binary Search Tree.", answer: "A Binary Tree has at most 2 children per node with no ordering. A BST maintains the property: left child < parent < right child. BST enables O(log n) search, insert, delete when balanced. Without balancing, a BST can degrade to O(n) — a linked list." },
  ],
  algorithms: [
    { question: "Explain the difference between BFS and DFS.", answer: "BFS (Breadth-First Search) explores all neighbors at current depth before going deeper — uses a queue, finds shortest path in unweighted graphs. DFS (Depth-First Search) explores as far as possible along each branch before backtracking — uses a stack/recursion, uses less memory." },
    { question: "What is dynamic programming?", answer: "DP solves complex problems by breaking them into overlapping subproblems and storing results to avoid redundant computation. Two approaches: top-down (memoization with recursion) and bottom-up (tabulation with iteration). Key: identify optimal substructure and overlapping subproblems." },
    { question: "What is the time complexity of common sorting algorithms?", answer: "Bubble/Selection/Insertion: O(n²) average/worst. Merge Sort: O(n log n) always, O(n) space. Quick Sort: O(n log n) average, O(n²) worst. Heap Sort: O(n log n) always, O(1) space. Counting/Radix Sort: O(n+k) for bounded integers." },
  ],
  dbms: [
    { question: "What is normalization and why is it important?", answer: "Normalization is the process of organizing a database to reduce redundancy and dependency. 1NF ensures atomic values, 2NF removes partial dependencies, 3NF removes transitive dependencies, BCNF ensures every determinant is a candidate key. It reduces data anomalies (insert, update, delete) and improves data integrity." },
    { question: "What is the difference between DBMS and RDBMS?", answer: "DBMS stores data as files without relationships between tables. RDBMS stores data in tabular form with relationships (foreign keys) between tables, supports ACID properties, uses SQL, and enforces data integrity through constraints. Examples: DBMS — file systems; RDBMS — MySQL, PostgreSQL, Oracle." },
    { question: "Explain ACID properties in a database.", answer: "Atomicity: a transaction is all-or-nothing. Consistency: database moves from one valid state to another. Isolation: concurrent transactions don't interfere with each other. Durability: once committed, data survives system failures. These properties ensure reliable transaction processing." },
    { question: "What are different types of keys in a database?", answer: "Primary Key: uniquely identifies each row. Foreign Key: references a primary key in another table. Candidate Key: minimal set of attributes that can uniquely identify a row. Super Key: any set that uniquely identifies rows. Composite Key: primary key made of multiple columns. Alternate Key: candidate key not chosen as primary key." },
    { question: "What is indexing and what are its types?", answer: "Indexing creates a data structure to speed up data retrieval. Types: Primary Index (on primary key), Secondary Index (on non-key attributes), Clustered Index (data physically sorted by index), Non-Clustered Index (separate structure pointing to data), Dense Index (entry for every record), Sparse Index (entry for every block)." },
    { question: "Explain different types of joins in SQL.", answer: "INNER JOIN: returns matching rows from both tables. LEFT JOIN: all rows from left + matching from right. RIGHT JOIN: all from right + matching from left. FULL OUTER JOIN: all rows from both tables. CROSS JOIN: cartesian product. SELF JOIN: a table joined with itself. NATURAL JOIN: auto-joins on common column names." },
    { question: "What is a deadlock in DBMS? How can it be prevented?", answer: "A deadlock occurs when two or more transactions wait for each other to release locks, creating a cycle. Prevention methods: Lock ordering (acquire locks in consistent order), Timeout-based (abort after timeout), Wait-Die and Wound-Wait schemes, Two-Phase Locking with deadlock detection using wait-for graphs." },
    { question: "What is denormalization? When would you use it?", answer: "Denormalization intentionally adds redundancy to a normalized database to improve read performance. It reduces the number of joins needed for frequent queries. Use it when: read-heavy workloads, reporting/analytics databases, data warehouses, or when query speed is more important than storage efficiency. Trade-off: faster reads but slower writes and risk of data inconsistency." },
    { question: "What is a view in SQL? What are its advantages?", answer: "A view is a virtual table based on a SELECT query. It doesn't store data physically but presents data from one or more tables. Advantages: simplifies complex queries, provides security by restricting access to specific columns/rows, presents data in a different format without altering the base table. Updatable views can modify underlying data; materialized views store results physically for faster access." },
    { question: "Explain the difference between DELETE, TRUNCATE, and DROP.", answer: "DELETE removes specific rows using WHERE clause, can be rolled back, fires triggers, and is DML. TRUNCATE removes all rows, cannot be rolled back (in most DBMS), resets auto-increment, doesn't fire triggers, and is DDL. DROP removes the entire table structure and data permanently. Use DELETE for selective removal, TRUNCATE to empty a table quickly, DROP to remove the table entirely." },
    { question: "What is a stored procedure? How does it differ from a function?", answer: "A stored procedure is a precompiled set of SQL statements stored in the database. Procedures can perform DML operations, return multiple values via OUT parameters, and don't need a return value. Functions must return a single value, can be used in SELECT statements, and are meant for computations. Procedures are called with CALL/EXEC; functions are called within SQL expressions." },
    { question: "What is a trigger in DBMS?", answer: "A trigger is a stored procedure that automatically executes in response to certain events (INSERT, UPDATE, DELETE) on a table. Types: BEFORE trigger (executes before the event), AFTER trigger (executes after), INSTEAD OF trigger (replaces the event). Use cases: audit logging, enforcing business rules, maintaining derived data, cascading updates." },
    { question: "What are the different isolation levels in a database?", answer: "Read Uncommitted: allows dirty reads. Read Committed: prevents dirty reads but allows non-repeatable reads. Repeatable Read: prevents dirty and non-repeatable reads but allows phantom reads. Serializable: highest isolation, prevents all anomalies but lowest concurrency. Higher isolation = more consistency but less performance. Default in most DBMS is Read Committed." },
    { question: "What is a cursor in SQL?", answer: "A cursor is a database object that allows row-by-row processing of query results. Types: Implicit (automatically created by DBMS for single-row operations) and Explicit (declared by the programmer for multi-row processing). Steps: DECLARE, OPEN, FETCH, CLOSE, DEALLOCATE. Use cursors when set-based operations aren't possible, but prefer set-based queries for performance." },
    { question: "What is referential integrity?", answer: "Referential integrity ensures that relationships between tables remain consistent. A foreign key in one table must reference an existing primary key in another table or be NULL. It prevents orphan records. Actions on violation: CASCADE (propagate changes), SET NULL, SET DEFAULT, RESTRICT/NO ACTION (prevent the operation). Enforced by foreign key constraints." },
    { question: "What is the difference between HAVING and WHERE clauses?", answer: "WHERE filters rows before grouping — it works on individual rows and cannot use aggregate functions. HAVING filters groups after GROUP BY — it works on aggregated results and can use aggregate functions like COUNT, SUM, AVG. Example: WHERE salary > 50000 filters individual rows; HAVING AVG(salary) > 50000 filters groups. Both can be used in the same query." },
    { question: "What is a subquery? What are correlated subqueries?", answer: "A subquery is a query nested inside another query. Types: Single-row (returns one value), Multi-row (returns multiple values, use IN/ANY/ALL), and Correlated (references outer query, executes once per outer row). Correlated subqueries are slower because they execute repeatedly. Example: SELECT * FROM emp e WHERE salary > (SELECT AVG(salary) FROM emp WHERE dept = e.dept)." },
    { question: "Explain the concept of a transaction log (WAL).", answer: "Write-Ahead Logging (WAL) is a technique where changes are first written to a log before being applied to the database. This ensures durability and crash recovery. On crash: committed transactions are replayed (REDO), uncommitted ones are undone (UNDO). The log contains: transaction ID, timestamp, old value, new value, and operation type. It enables point-in-time recovery." },
    { question: "What is the difference between clustered and non-clustered index?", answer: "Clustered index physically sorts and stores data rows in the table based on the index key. Only one per table. Non-clustered index creates a separate structure with pointers to data rows. Multiple per table. Clustered is faster for range queries; non-clustered is better for specific lookups. Primary key usually creates a clustered index automatically." },
    { question: "What is an ER diagram? Explain its components.", answer: "An Entity-Relationship diagram models the database structure visually. Components: Entities (rectangles — tables), Attributes (ovals — columns), Relationships (diamonds — connections). Cardinality: 1:1, 1:N, M:N. Strong entity has its own primary key; weak entity depends on a strong entity. Participation: total (double line) or partial (single line)." },
    { question: "What is the difference between UNION and UNION ALL?", answer: "UNION combines result sets of two queries and removes duplicate rows (requires sorting/comparison). UNION ALL combines result sets keeping all duplicates (faster, no sorting needed). Both require the same number of columns with compatible data types. Use UNION ALL when duplicates are acceptable or impossible — it's more performant." },
    { question: "What are aggregate functions in SQL?", answer: "Aggregate functions perform calculations on a set of values and return a single result. Common ones: COUNT (number of rows), SUM (total of numeric column), AVG (average), MIN (smallest value), MAX (largest value). Used with GROUP BY to aggregate per group. NULL values are ignored by all aggregates except COUNT(*). Can be combined with HAVING for filtering." },
    { question: "What is a schema in DBMS?", answer: "A schema is the logical structure/blueprint of a database. It defines tables, columns, data types, relationships, constraints, indexes, and views. Three schema architecture: External schema (user views), Conceptual schema (logical structure), Internal schema (physical storage). Schema is defined using DDL (CREATE, ALTER, DROP) and doesn't change frequently — data within it changes." },
    { question: "Explain two-phase locking protocol.", answer: "Two-Phase Locking (2PL) ensures serializability of transactions. Phase 1 (Growing): transaction acquires locks but cannot release any. Phase 2 (Shrinking): transaction releases locks but cannot acquire new ones. Strict 2PL: holds all exclusive locks until commit/abort — prevents cascading rollbacks. Rigorous 2PL: holds ALL locks until end — simplest but most restrictive." },
    { question: "What is the difference between OLTP and OLAP?", answer: "OLTP (Online Transaction Processing): handles day-to-day transactions, many short queries, normalized schema, row-oriented storage, high concurrency (banking, e-commerce). OLAP (Online Analytical Processing): handles complex analytical queries, few long queries, denormalized/star schema, column-oriented storage, read-heavy (business intelligence, reporting, data warehousing)." },
    { question: "What is a B+ tree index?", answer: "B+ tree is the most common index structure in databases. It's a balanced tree where: all data pointers are at leaf nodes, leaf nodes are linked (supports range queries efficiently), internal nodes only store keys for routing. Properties: logarithmic search time O(log n), self-balancing, optimized for disk reads (high fan-out reduces tree height). Most RDBMS default index type." },
    { question: "What is a materialized view?", answer: "A materialized view stores the result of a query physically on disk, unlike a regular view which is computed on each access. It provides faster reads for expensive queries (joins, aggregations). Must be refreshed periodically: ON COMMIT (updated after each transaction), ON DEMAND (manual refresh), or incrementally. Trade-off: faster reads but stale data between refreshes and extra storage." },
    { question: "Explain the concept of functional dependency.", answer: "A functional dependency X → Y means the value of attribute X uniquely determines the value of Y. Example: StudentID → StudentName (knowing the ID determines the name). Types: Full FD (Y depends on the entire key), Partial FD (Y depends on part of a composite key — violates 2NF), Transitive FD (X → Y → Z implies X → Z — violates 3NF). FDs are the basis for normalization." },
    { question: "What is a CHECK constraint?", answer: "A CHECK constraint enforces a condition on column values. It ensures that data inserted or updated in a column satisfies a boolean expression. Example: CHECK (age >= 18), CHECK (salary > 0), CHECK (status IN ('active', 'inactive')). It's enforced at the database level, providing data integrity regardless of the application. Can reference multiple columns in the same row." },
    { question: "What is database partitioning?", answer: "Partitioning splits a large table into smaller, more manageable pieces while appearing as one table. Horizontal partitioning: splits rows (e.g., by date range, region). Vertical partitioning: splits columns (frequently vs rarely accessed). Benefits: faster queries (scan only relevant partition), easier maintenance, parallel processing. Types: Range, List, Hash, Composite partitioning." },
  ],
  "computer network": [
    { question: "Explain the OSI model and its 7 layers.", answer: "Layer 1 Physical: bits over media. Layer 2 Data Link: frames, MAC addressing, error detection. Layer 3 Network: IP addressing, routing. Layer 4 Transport: TCP/UDP, end-to-end delivery. Layer 5 Session: session management. Layer 6 Presentation: encryption, compression, translation. Layer 7 Application: HTTP, FTP, DNS, user interface." },
    { question: "What is the difference between TCP and UDP?", answer: "TCP is connection-oriented, reliable (guaranteed delivery with acknowledgments), ordered, has flow/congestion control, and is slower (HTTP, FTP, email). UDP is connectionless, unreliable (no guaranteed delivery), unordered, faster, and has lower overhead (DNS, video streaming, gaming, VoIP)." },
    { question: "What happens when you type a URL in the browser?", answer: "1) Browser checks cache, then DNS resolution (recursive query to resolve domain to IP). 2) TCP three-way handshake (SYN, SYN-ACK, ACK). 3) TLS handshake if HTTPS. 4) HTTP request sent. 5) Server processes and sends response. 6) Browser parses HTML, loads CSS/JS, renders the page. 7) Connection may be kept alive or closed." },
    { question: "Explain the difference between IPv4 and IPv6.", answer: "IPv4: 32-bit addresses (4.3 billion), dotted decimal (192.168.1.1), header 20-60 bytes, uses NAT. IPv6: 128-bit addresses (3.4x10^38), hexadecimal with colons (2001:db8::1), header fixed at 40 bytes, built-in IPSec, no NAT needed, auto-configuration via SLAAC." },
    { question: "What is subnetting and why is it used?", answer: "Subnetting divides a large network into smaller logical sub-networks. It improves security (isolate segments), reduces broadcast traffic, optimizes IP address usage, and simplifies management. A subnet mask (e.g., 255.255.255.0 or /24) determines which part of the IP is the network vs host portion." },
    { question: "Explain ARP (Address Resolution Protocol).", answer: "ARP maps an IP address (Layer 3) to a MAC address (Layer 2) within a local network. The sender broadcasts an ARP request asking 'Who has this IP?'. The device with that IP responds with its MAC address. This mapping is cached in the ARP table for future use. RARP does the reverse (MAC to IP)." },
    { question: "What is the three-way handshake in TCP?", answer: "Step 1: Client sends SYN (synchronize) packet with an initial sequence number. Step 2: Server responds with SYN-ACK (synchronize-acknowledge), acknowledging client's SYN and sending its own sequence number. Step 3: Client sends ACK, acknowledging server's SYN. Connection is now established and data transfer can begin." },
    { question: "What is DNS and how does it work?", answer: "DNS (Domain Name System) translates human-readable domain names to IP addresses. Process: browser cache → OS cache → router cache → ISP's recursive resolver → root server → TLD server (.com) → authoritative name server. Record types: A (IPv4), AAAA (IPv6), CNAME (alias), MX (mail), NS (nameserver), TXT (text). DNS uses UDP port 53 for queries." },
    { question: "What is NAT (Network Address Translation)?", answer: "NAT translates private IP addresses to public IP addresses and vice versa, allowing multiple devices to share a single public IP. Types: Static NAT (1:1 mapping), Dynamic NAT (pool of public IPs), PAT/NAT Overload (many-to-one using port numbers). Benefits: conserves IPv4 addresses, provides security by hiding internal network structure. Limitation: breaks end-to-end connectivity." },
    { question: "Explain the difference between a hub, switch, and router.", answer: "Hub: Layer 1 device, broadcasts data to all ports, no intelligence, creates collisions. Switch: Layer 2 device, uses MAC address table to forward frames to specific ports, reduces collisions, creates separate collision domains. Router: Layer 3 device, forwards packets between different networks using IP addresses, performs NAT, provides firewall capability." },
    { question: "What is DHCP and how does it work?", answer: "DHCP (Dynamic Host Configuration Protocol) automatically assigns IP addresses and network configuration to devices. Process (DORA): 1) Discover — client broadcasts request. 2) Offer — server offers an IP. 3) Request — client accepts the offer. 4) Acknowledge — server confirms assignment. DHCP provides: IP address, subnet mask, default gateway, DNS servers. Lease has an expiry time." },
    { question: "What is the difference between HTTP and HTTPS?", answer: "HTTP transfers data in plain text — anyone intercepting can read it. HTTPS uses TLS/SSL encryption on top of HTTP. TLS handshake: client hello → server hello + certificate → key exchange → encrypted communication. HTTPS uses port 443 (HTTP uses 80). HTTPS provides: encryption, authentication (server identity via certificate), and data integrity." },
    { question: "What is a VLAN (Virtual Local Area Network)?", answer: "A VLAN logically segments a physical network into separate broadcast domains. Devices in the same VLAN can communicate as if on the same LAN, even if physically separated. Benefits: security isolation, reduced broadcast traffic, flexible grouping (by department, not location). Trunk ports carry traffic for multiple VLANs using 802.1Q tagging. Inter-VLAN routing requires a Layer 3 device." },
    { question: "Explain TCP flow control and congestion control.", answer: "Flow control: receiver advertises a window size in ACK packets, telling the sender how much data it can accept. Prevents receiver buffer overflow. Sliding window protocol manages this. Congestion control: prevents network overload. Algorithms: Slow Start (exponential growth), Congestion Avoidance (linear growth), Fast Retransmit/Recovery (recover from loss without timeout). TCP uses AIMD (Additive Increase, Multiplicative Decrease)." },
    { question: "What is a firewall and what are its types?", answer: "A firewall monitors and filters incoming/outgoing network traffic based on security rules. Types: Packet Filtering (inspects headers — IP, port), Stateful Inspection (tracks connection state), Application Layer/Proxy (inspects payload content), Next-Gen Firewall (deep packet inspection + IDS/IPS). Can be hardware (network-level) or software (host-level). Uses ACLs (Access Control Lists) to define rules." },
    { question: "What is the difference between unicast, broadcast, and multicast?", answer: "Unicast: one-to-one communication — data sent from one source to one specific destination. Broadcast: one-to-all — data sent to all devices in the network (limited broadcast: 255.255.255.255). Multicast: one-to-many — data sent to a group of interested devices using multicast addresses (224.0.0.0 to 239.255.255.255). Multicast is efficient for streaming, gaming, and live events." },
    { question: "What is ICMP and what is it used for?", answer: "ICMP (Internet Control Message Protocol) is a network layer protocol used for error reporting and diagnostics. It doesn't transport data. Common uses: ping (echo request/reply to test connectivity), traceroute (TTL-based path discovery), destination unreachable messages, time exceeded messages. ICMP is essential for network troubleshooting but often restricted by firewalls." },
    { question: "Explain the concept of routing and types of routing.", answer: "Routing is the process of selecting the best path for data packets to travel from source to destination across networks. Static routing: manually configured routes, simple but doesn't adapt. Dynamic routing: uses protocols to automatically learn and update routes. Protocols: RIP (distance vector, hop count), OSPF (link state, Dijkstra), BGP (path vector, inter-AS routing). Routing table stores: destination, next hop, metric, interface." },
    { question: "What is a proxy server?", answer: "A proxy server acts as an intermediary between clients and servers. Forward proxy: client-side, hides client identity (browsing anonymity, content filtering, caching). Reverse proxy: server-side, hides server identity (load balancing, SSL termination, caching, DDoS protection). Examples: Squid (forward), Nginx (reverse). Transparent proxy intercepts without client configuration." },
    { question: "What is the difference between FTP, SFTP, and SCP?", answer: "FTP (File Transfer Protocol): transfers files using two connections (control on port 21, data on port 20), unencrypted, supports directory listing. SFTP (SSH File Transfer Protocol): runs over SSH (port 22), encrypted, supports resume and directory operations. SCP (Secure Copy Protocol): also over SSH, simpler, only copies files (no directory listing or resume). SFTP is the recommended choice." },
    { question: "What is a socket in networking?", answer: "A socket is an endpoint for communication between two machines, identified by an IP address and port number combination (e.g., 192.168.1.1:8080). Types: Stream socket (TCP — reliable, ordered), Datagram socket (UDP — fast, unordered). Socket programming involves: socket(), bind(), listen(), accept(), connect(), send(), recv(), close(). The client-server model is built on sockets." },
    { question: "Explain SSL/TLS handshake process.", answer: "1) Client Hello: sends supported TLS versions, cipher suites, and a random number. 2) Server Hello: selects cipher suite, sends certificate and random number. 3) Client verifies certificate against trusted CAs. 4) Key Exchange: client generates pre-master secret, encrypts with server's public key. 5) Both derive session keys from the pre-master secret. 6) Finished messages confirm encryption works. All subsequent data is encrypted with symmetric keys." },
    { question: "What is the difference between circuit switching and packet switching?", answer: "Circuit switching: dedicated communication path established for entire session (telephone networks). Guaranteed bandwidth but wastes resources during silence. Packet switching: data split into packets that independently find routes (internet). Efficient resource utilization but variable latency. Types of packet switching: Datagram (each packet routed independently — IP) and Virtual Circuit (path established first — ATM, MPLS)." },
    { question: "What is a CDN (Content Delivery Network)?", answer: "A CDN is a distributed network of servers (edge nodes) that cache and deliver content from locations closest to users. Benefits: reduced latency, lower origin server load, DDoS protection, high availability. How it works: DNS resolves to nearest edge server, if cache hit → serve directly, if cache miss → fetch from origin and cache. Examples: Cloudflare, AWS CloudFront, Akamai." },
    { question: "What is CORS (Cross-Origin Resource Sharing)?", answer: "CORS is a security mechanism that allows or restricts web pages from making requests to a different domain than the one serving the page. Browsers enforce same-origin policy by default. Server responds with headers: Access-Control-Allow-Origin, Access-Control-Allow-Methods, Access-Control-Allow-Headers. Preflight request (OPTIONS) is sent for non-simple requests. Essential for APIs consumed by web frontends on different domains." },
    { question: "Explain the concept of a MAC address.", answer: "A MAC (Media Access Control) address is a unique 48-bit hardware identifier assigned to a network interface card (NIC) by the manufacturer. Format: 6 pairs of hex digits (e.g., AA:BB:CC:DD:EE:FF). First 3 bytes = OUI (manufacturer), last 3 bytes = device ID. Operates at Layer 2 (Data Link). Used for local network communication. Unlike IP addresses, MAC addresses don't change (though can be spoofed)." },
  ],
  "computer fundamental": [
    { question: "What is the difference between RAM and ROM?", answer: "RAM (Random Access Memory) is volatile — data is lost when power is off. It's read-write, faster, and used for active programs. ROM (Read Only Memory) is non-volatile — data persists without power. It stores firmware/BIOS. Types of RAM: SRAM, DRAM. Types of ROM: PROM, EPROM, EEPROM." },
    { question: "Explain the Von Neumann architecture.", answer: "Von Neumann architecture has: CPU (ALU + Control Unit), Memory (stores both data and instructions), Input/Output devices, and a Bus system connecting them. Instructions are fetched from memory, decoded, and executed sequentially. The bottleneck is that data and instructions share the same memory bus." },
    { question: "What is the difference between compiler and interpreter?", answer: "Compiler translates entire source code to machine code before execution, produces an executable file, shows all errors at once, and runs faster (C, C++, Java). Interpreter translates and executes line by line, no separate file, shows errors one at a time, and is slower but easier to debug (Python, JavaScript, Ruby)." },
    { question: "What is cache memory and how does it work?", answer: "Cache is a small, very fast memory between CPU and RAM that stores frequently accessed data. It uses locality of reference — temporal (recently accessed data) and spatial (nearby data). Levels: L1 (smallest, fastest, on CPU), L2 (larger, slightly slower), L3 (largest, shared among cores). Cache hit = data found; cache miss = fetch from RAM." },
    { question: "Explain number systems and conversions.", answer: "Binary (base 2): uses 0,1. Octal (base 8): uses 0-7. Decimal (base 10): uses 0-9. Hexadecimal (base 16): uses 0-9, A-F. Conversion: decimal to binary — divide by 2, collect remainders. Binary to decimal — multiply each bit by 2^position. 1 hex digit = 4 binary bits. 1 octal digit = 3 binary bits." },
    { question: "What are logic gates and their types?", answer: "Logic gates perform boolean operations on binary inputs. AND: output 1 only if all inputs are 1. OR: output 1 if any input is 1. NOT: inverts input. NAND: NOT AND (universal gate). NOR: NOT OR (universal gate). XOR: output 1 if inputs differ. XNOR: output 1 if inputs are same. NAND and NOR can implement any circuit." },
    { question: "What is the CPU and what are its components?", answer: "CPU (Central Processing Unit) is the brain of the computer. Components: ALU (Arithmetic Logic Unit) — performs arithmetic and logical operations. CU (Control Unit) — fetches, decodes, and executes instructions, controls data flow. Registers — small, fast storage (PC, IR, MAR, MDR, accumulator). Clock — synchronizes operations. Modern CPUs have multiple cores for parallel processing." },
    { question: "What is the difference between SRAM and DRAM?", answer: "SRAM (Static RAM): uses flip-flops (6 transistors per bit), faster, no refresh needed, more expensive, used for cache memory. DRAM (Dynamic RAM): uses capacitors (1 transistor + 1 capacitor per bit), slower, needs periodic refresh, cheaper, used for main memory. SRAM retains data as long as power is on; DRAM loses charge and must be refreshed thousands of times per second." },
    { question: "What is the instruction cycle (fetch-decode-execute)?", answer: "The CPU processes each instruction in a cycle: 1) Fetch — retrieve instruction from memory (address in PC) into IR. 2) Decode — CU interprets the instruction and identifies the operation and operands. 3) Execute — ALU performs the operation. 4) Store — result written back to register or memory. PC increments to point to next instruction. Pipelining overlaps these stages for multiple instructions." },
    { question: "What is pipelining in computer architecture?", answer: "Pipelining overlaps the execution of multiple instructions by dividing the instruction cycle into stages (fetch, decode, execute, memory, write-back). While one instruction executes, the next is decoded, and another is fetched — like an assembly line. Increases throughput (instructions per cycle) but doesn't reduce individual instruction time. Hazards: data dependency, control (branch), structural." },
    { question: "Explain the difference between RISC and CISC.", answer: "RISC (Reduced Instruction Set Computer): simple instructions, fixed length, executes in one clock cycle, uses more registers, relies on compiler optimization (ARM, MIPS). CISC (Complex Instruction Set Computer): complex instructions, variable length, may take multiple cycles, uses fewer registers, hardware handles complexity (x86, Intel). Modern processors often combine both approaches." },
    { question: "What is virtual memory?", answer: "Virtual memory is a memory management technique that creates an illusion of a larger memory space than physically available. It uses disk space (swap/page file) as extension of RAM. Each process gets its own virtual address space mapped to physical memory via page tables. Benefits: process isolation, running programs larger than RAM, efficient memory utilization. Trade-off: page faults cause disk access which is slow." },
    { question: "What is DMA (Direct Memory Access)?", answer: "DMA allows hardware devices to transfer data directly to/from memory without CPU involvement. The CPU initiates the transfer, then the DMA controller handles it while the CPU does other work. Types: Burst mode (DMA takes over bus), Cycle stealing (DMA uses bus for one word at a time), Transparent (DMA uses bus only when CPU doesn't need it). Improves I/O performance significantly." },
    { question: "What is the difference between primary and secondary storage?", answer: "Primary storage (main memory): RAM and cache — volatile, fast, directly accessible by CPU, limited capacity, expensive per GB. Secondary storage: HDD, SSD, USB drives — non-volatile, slower, not directly accessible by CPU (goes through I/O), large capacity, cheaper per GB. Data must be loaded from secondary to primary storage before CPU can process it." },
    { question: "What is an interrupt in computer systems?", answer: "An interrupt is a signal that temporarily halts the current process to handle a higher-priority event. Types: Hardware interrupt (from I/O devices — keyboard, mouse), Software interrupt (from programs — system calls, exceptions), Timer interrupt (from clock — scheduling). Process: save current state → identify interrupt → execute ISR (Interrupt Service Routine) → restore state → resume. Managed by interrupt controller." },
    { question: "Explain Boolean algebra and its laws.", answer: "Boolean algebra operates on binary values (0, 1) with three basic operations: AND (.), OR (+), NOT ('). Key laws: Identity (A+0=A, A.1=A), Null (A+1=1, A.0=0), Complement (A+A'=1, A.A'=0), Idempotent (A+A=A), De Morgan's (A+B)' = A'.B' and (A.B)' = A'+B'. Used for simplifying logic circuits. Karnaugh maps (K-maps) provide a visual simplification method." },
    { question: "What is the difference between parallel and serial data transmission?", answer: "Serial transmission: sends data one bit at a time over a single channel. Slower but simpler, less interference, works over long distances (USB, SATA). Parallel transmission: sends multiple bits simultaneously over multiple channels. Faster for short distances but suffers from signal skew and cross-talk at longer distances (old printer ports, memory bus). Modern high-speed is serial (USB 3.0, PCIe)." },
    { question: "What is an operating system and what are its functions?", answer: "An OS is system software that manages hardware resources and provides services to applications. Functions: Process management (scheduling, creation, termination), Memory management (allocation, virtual memory, paging), File system management (create, read, write, delete), I/O management (device drivers, buffering), Security (authentication, access control), User interface (CLI, GUI)." },
    { question: "What is the difference between 32-bit and 64-bit processors?", answer: "32-bit processors can address 2^32 bytes = 4 GB of RAM maximum. 64-bit processors can theoretically address 2^64 bytes (16 exabytes). 64-bit offers: more RAM support, better performance for large data, larger registers for faster computation. 64-bit OS can run 32-bit programs (backward compatible) but not vice versa. Most modern processors and OS are 64-bit." },
    { question: "What is the bus system in a computer?", answer: "A bus is a communication system that transfers data between computer components. Types: Data bus (carries actual data — bidirectional, width determines how much data per transfer), Address bus (carries memory addresses — unidirectional, width determines addressable memory), Control bus (carries control signals — read/write, interrupt, clock). Bus width and speed affect overall system performance." },
    { question: "Explain the concept of addressing modes.", answer: "Addressing modes specify how to find the operand of an instruction. Common modes: Immediate (operand in instruction itself), Register (operand in a register), Direct (memory address in instruction), Indirect (address of address in instruction), Indexed (base address + offset), Relative (PC + offset for branches). Different modes offer trade-offs between flexibility, speed, and instruction size." },
    { question: "What is the difference between ASCII and Unicode?", answer: "ASCII (American Standard Code for Information Interchange): 7-bit encoding, 128 characters (English letters, digits, symbols, control characters). Extended ASCII uses 8 bits for 256 characters. Unicode: supports all world languages — UTF-8 (1-4 bytes, backward compatible with ASCII), UTF-16 (2-4 bytes), UTF-32 (4 bytes fixed). UTF-8 is the most widely used encoding on the web." },
    { question: "What is a multiplexer and demultiplexer?", answer: "Multiplexer (MUX): selects one of many input signals and forwards it to a single output line. Uses select lines to choose the input (2^n inputs need n select lines). Demultiplexer (DEMUX): takes a single input and routes it to one of many output lines. MUX is used for data selection; DEMUX for data distribution. Together they enable efficient use of communication channels." },
    { question: "What is the difference between a microprocessor and a microcontroller?", answer: "Microprocessor: CPU only — needs external RAM, ROM, I/O ports, and peripherals (e.g., Intel i7, AMD Ryzen). Used in computers and servers. Microcontroller: CPU + RAM + ROM + I/O + timers on a single chip (e.g., Arduino/ATmega, ESP32). Used in embedded systems (washing machines, cars, IoT). Microcontrollers are cheaper, lower power, and self-contained; microprocessors are more powerful." },
  ],
  "operating system": [
    { question: "What is a process vs a thread?", answer: "A process is an independent program in execution with its own memory space, file handles, and resources. A thread is the smallest unit of execution within a process — threads share the process's memory and resources. Creating threads is lighter than processes. Context switching between threads is faster. Processes communicate via IPC; threads share memory directly." },
    { question: "Explain different CPU scheduling algorithms.", answer: "FCFS: first come, first served — simple but causes convoy effect. SJF: shortest job first — optimal average wait time but needs burst prediction. Round Robin: time quantum-based preemption — fair but high context switching. Priority: based on priority values — may cause starvation (solve with aging). Multilevel Queue: separate queues for different process types." },
    { question: "What is virtual memory?", answer: "Virtual memory extends physical RAM by using disk space (swap/page file). Each process gets a virtual address space mapped to physical memory via page tables. Benefits: run programs larger than physical RAM, memory isolation between processes, efficient memory allocation. Concepts: paging, page faults, page replacement algorithms (LRU, FIFO, Optimal)." },
    { question: "Explain deadlock: conditions and prevention.", answer: "Deadlock occurs when processes wait indefinitely for resources held by each other. Four necessary conditions (Coffman): 1) Mutual Exclusion — resource held exclusively. 2) Hold and Wait — holding one, waiting for another. 3) No Preemption — can't forcibly take resources. 4) Circular Wait — circular dependency chain. Prevent by breaking any one condition." },
    { question: "What is paging and segmentation?", answer: "Paging divides memory into fixed-size pages (logical) and frames (physical). Simple, no external fragmentation, but has internal fragmentation. Segmentation divides memory into variable-size segments based on logical divisions (code, data, stack). More meaningful, supports sharing, but causes external fragmentation. Modern systems combine both." },
    { question: "Explain different types of operating systems.", answer: "Batch OS: jobs processed in batches without user interaction. Time-Sharing OS: CPU time shared among multiple users (Unix). Real-Time OS: guaranteed response within deadlines (RTOS for embedded systems). Distributed OS: manages multiple computers as one system. Network OS: provides network services. Mobile OS: Android, iOS for mobile devices." },
    { question: "What is the difference between mutex and semaphore?", answer: "Mutex (Mutual Exclusion): binary lock, only the thread that locked it can unlock it, used for exclusive resource access. Semaphore: integer counter, can be signaled by any thread. Binary semaphore is similar to mutex but without ownership. Counting semaphore allows N concurrent accesses. Mutex prevents priority inversion with priority inheritance." },
    { question: "What is context switching?", answer: "Context switching is the process of saving the state (registers, PC, stack pointer) of the currently running process and loading the saved state of the next process to run. It allows multi-tasking on a single CPU. Overhead: saving/restoring registers, flushing TLB/cache, memory mapping changes. Thread context switching is faster than process switching because threads share the same address space." },
    { question: "Explain page replacement algorithms.", answer: "When a page fault occurs and no free frame is available, a page must be replaced. FIFO: replace the oldest page — simple but suffers from Belady's anomaly. LRU (Least Recently Used): replace the page not used for the longest time — good performance but expensive to implement. Optimal: replace the page that won't be used for the longest future time — theoretical best but requires future knowledge. Clock/Second Chance: approximation of LRU." },
    { question: "What is thrashing in operating systems?", answer: "Thrashing occurs when the system spends more time swapping pages in/out of memory than executing processes. It happens when there are too many processes and each gets too few frames, causing frequent page faults. The CPU utilization drops despite high demand. Solution: reduce the degree of multiprogramming, use working set model, or increase physical memory." },
    { question: "What is a system call? Give examples.", answer: "A system call is the interface between a user program and the OS kernel. It allows programs to request services from the OS. Categories: Process control (fork, exec, exit, wait), File management (open, read, write, close), Device management (ioctl), Information maintenance (getpid, time), Communication (pipe, shmget, mmap). System calls involve switching from user mode to kernel mode (trap instruction)." },
    { question: "What is the difference between preemptive and non-preemptive scheduling?", answer: "Non-preemptive: once a process starts executing, it runs until it completes or voluntarily yields (FCFS, SJF without preemption). Simpler but can cause long wait times. Preemptive: the OS can interrupt a running process to allocate CPU to another process (Round Robin, SRTF, Priority with preemption). Better response time but higher context-switching overhead. Most modern OS use preemptive scheduling." },
    { question: "Explain the producer-consumer problem.", answer: "A classic synchronization problem: a producer creates items and places them in a shared buffer; a consumer removes items. Challenges: buffer overflow (producer adds to full buffer), buffer underflow (consumer takes from empty buffer), race condition (both access buffer simultaneously). Solution: use semaphores — mutex for mutual exclusion, empty semaphore (counts free slots), full semaphore (counts available items)." },
    { question: "What is the Banker's Algorithm?", answer: "Banker's Algorithm is a deadlock avoidance algorithm. It checks if granting a resource request will leave the system in a safe state (a sequence exists where all processes can finish). Data structures: Available (free resources), Max (maximum demand per process), Allocation (currently held), Need (Max - Allocation). If a request keeps the system safe, grant it; otherwise, the process must wait." },
    { question: "What is the difference between internal and external fragmentation?", answer: "Internal fragmentation: wasted space inside an allocated memory block — occurs with fixed-size allocation (paging). Example: process needs 3.5 KB but gets a 4 KB page, wasting 0.5 KB. External fragmentation: free memory exists but is non-contiguous — occurs with variable-size allocation (segmentation). Example: total free memory is 10 KB but split into scattered small blocks, can't fit a 10 KB process." },
    { question: "What is IPC (Inter-Process Communication)?", answer: "IPC mechanisms allow processes to exchange data and synchronize. Methods: Pipes (unidirectional byte stream between related processes), Named Pipes/FIFOs (between unrelated processes), Message Queues (structured message passing), Shared Memory (fastest — processes read/write common memory region), Sockets (network communication), Signals (asynchronous notifications). Shared memory is fastest; sockets are most versatile." },
    { question: "Explain disk scheduling algorithms.", answer: "Disk scheduling determines the order in which disk I/O requests are serviced. FCFS: serve in arrival order — simple but high seek time. SSTF (Shortest Seek Time First): serve nearest request — good throughput but may starve distant requests. SCAN (elevator): move head in one direction servicing requests, reverse at end. C-SCAN: only service in one direction, jump back. LOOK/C-LOOK: reverse at last request rather than end." },
    { question: "What is a file system and what are common types?", answer: "A file system organizes and manages how data is stored and retrieved on a storage device. Components: files, directories, metadata (permissions, timestamps), allocation tables. Types: FAT32 (simple, cross-platform, 4 GB file limit), NTFS (Windows — journaling, ACLs, large files), ext4 (Linux — journaling, large volumes), APFS (macOS — encryption, snapshots). Journaling prevents corruption on crash." },
    { question: "What is the difference between user mode and kernel mode?", answer: "User mode: restricted access — applications run here and cannot directly access hardware or critical memory. Kernel mode: full access — OS kernel runs here with unrestricted access to hardware and memory. Switching from user to kernel mode happens via system calls (trap instruction). This separation provides: security (buggy programs can't crash OS), stability, and resource protection." },
    { question: "Explain the concept of a process state diagram.", answer: "A process goes through states: New (created), Ready (in ready queue, waiting for CPU), Running (executing on CPU), Waiting/Blocked (waiting for I/O or event), Terminated (finished execution). Transitions: New → Ready (admitted), Ready → Running (scheduler dispatch), Running → Ready (preempted/time quantum expired), Running → Waiting (I/O request), Waiting → Ready (I/O complete), Running → Terminated (exit)." },
    { question: "What is the difference between a monolithic kernel and a microkernel?", answer: "Monolithic kernel: entire OS runs in kernel space — file system, drivers, networking, all in one address space. Fast (no IPC overhead) but a bug in any component can crash the whole OS (Linux, Windows). Microkernel: minimal kernel (scheduling, IPC, memory) — other services run as user-space processes. More stable and modular but slower due to IPC overhead (Minix, QNX). Hybrid kernels combine both (macOS, Windows NT)." },
    { question: "What is a race condition? How do you prevent it?", answer: "A race condition occurs when multiple processes/threads access shared data concurrently and the result depends on the timing of execution. Example: two threads both read a counter as 5, increment to 6, and write — counter should be 7 but becomes 6. Prevention: mutual exclusion (mutex/locks), semaphores, monitors, atomic operations, or lock-free data structures. The critical section must be protected." },
    { question: "Explain the working set model.", answer: "The working set model estimates the set of pages a process is actively using during a time window. If the OS allocates at least as many frames as the working set size, the process runs efficiently with few page faults. If frames are fewer than the working set, thrashing occurs. The OS can use the working set model to decide whether to admit new processes (if total working sets exceed available memory, don't admit)." },
    { question: "What is the difference between long-term, short-term, and medium-term schedulers?", answer: "Long-term scheduler (job scheduler): decides which jobs to admit from disk to the ready queue — controls the degree of multiprogramming. Short-term scheduler (CPU scheduler): selects which ready process gets the CPU next — runs very frequently (milliseconds). Medium-term scheduler: handles swapping — moves processes between memory and disk to manage memory pressure. Not all OS have all three schedulers." },
    { question: "What is copy-on-write (COW)?", answer: "Copy-on-write is a memory optimization used during fork(). Instead of copying the parent's entire memory for the child process, both share the same pages marked as read-only. When either process writes to a page, only then is that page copied (creating a private copy). This makes fork() very fast because most pages are never modified. Used extensively in modern OS and also in file systems (Btrfs, ZFS)." },
  ],
  hld: [
    { question: "What is High-Level Design and how does it differ from Low-Level Design?", answer: "HLD defines the system architecture — components, their interactions, data flow, and technology choices at a macro level. It answers WHAT the system does and HOW components communicate. LLD dives into the implementation details — class diagrams, database schemas, API contracts, and algorithms. HLD is for architects; LLD is for developers." },
    { question: "How would you design a URL shortener like bit.ly?", answer: "Components: Load Balancer → Web Servers → Application Servers → Database + Cache. Use Base62 encoding of auto-increment ID or hash for short URLs. Store mapping in a relational DB (key-value). Use Redis cache for hot URLs. Read-heavy system (100:1 read:write). Add analytics service for click tracking. Scale with database sharding on short URL hash." },
    { question: "Explain the CAP theorem with examples.", answer: "CAP states a distributed system can guarantee only 2 of 3: Consistency (all nodes see same data), Availability (every request gets a response), Partition Tolerance (system works despite network failures). CP: MongoDB, HBase — consistent but may be unavailable during partitions. AP: Cassandra, DynamoDB — available but may return stale data. CA: only in single-node systems (traditional RDBMS)." },
    { question: "How would you design a chat application like WhatsApp?", answer: "Use WebSocket connections for real-time messaging. Components: Chat Server (manages WebSocket connections), Message Queue (Kafka for async delivery), Presence Service (online/offline status), Media Service (S3 for images/videos), Notification Service (push for offline users). Use message queues for guaranteed delivery. Store messages in Cassandra (write-heavy, time-series). Last-seen using heartbeats." },
    { question: "What is database sharding and when would you use it?", answer: "Sharding horizontally partitions data across multiple database instances. Each shard holds a subset of data. Strategies: Hash-based (consistent hashing on user ID), Range-based (by date, geography), Directory-based (lookup table). Use when: single DB can't handle load, need horizontal scaling. Challenges: cross-shard queries, rebalancing, maintaining consistency." },
    { question: "How do you ensure high availability in system design?", answer: "Redundancy: multiple instances of every component. Load balancing: distribute traffic (active-active or active-passive). Database replication: master-slave or multi-master. Auto-scaling: handle traffic spikes. Health checks: detect and route around failures. CDN: cache static content at edge. Circuit breakers: prevent cascade failures. Geographic distribution: multi-region deployment." },
    { question: "What is consistent hashing?", answer: "Consistent hashing distributes data across nodes in a ring structure. When a node is added/removed, only ~1/n keys need redistribution (vs all keys in simple hashing). Each node is placed on a hash ring; keys are assigned to the next node clockwise. Virtual nodes improve balance by placing each physical node at multiple ring positions. Used in: DynamoDB, Cassandra, load balancers, CDNs." },
    { question: "How would you design a news feed system like Facebook?", answer: "Two approaches: Fan-out on write (push: when user posts, push to all followers' feeds — fast reads, slow writes, good for users with few followers) and Fan-out on read (pull: compute feed at read time — slow reads, good for celebrities). Hybrid: push for normal users, pull for celebrities. Components: Post Service, Feed Generation Service, Feed Cache (Redis), Ranking Service, Notification Service." },
    { question: "What is a message queue and when would you use one?", answer: "A message queue decouples producers (senders) from consumers (receivers). Producers send messages to the queue; consumers process them asynchronously. Benefits: decoupling, load leveling, fault tolerance, scalability. Use cases: order processing, email sending, video transcoding, event processing. Examples: Kafka (high throughput, log-based), RabbitMQ (flexible routing), SQS (managed). Patterns: point-to-point, pub/sub." },
    { question: "Explain microservices vs monolithic architecture.", answer: "Monolith: single deployable unit, shared database, simple to develop initially, but becomes complex, hard to scale independently, single point of failure. Microservices: small independent services with their own databases, independently deployable/scalable, technology-agnostic, but adds complexity (service discovery, distributed transactions, network latency). Start monolith, split when you understand domain boundaries." },
    { question: "What is a rate limiter and how would you design one?", answer: "A rate limiter controls how many requests a user/IP can make in a time window. Algorithms: Token Bucket (tokens added at fixed rate, request consumes a token), Leaky Bucket (requests processed at fixed rate), Fixed Window (counter per time window), Sliding Window (weighted combination). Implementation: Redis with INCR + EXPIRE. Return 429 Too Many Requests when limit exceeded. Place at API gateway or as middleware." },
    { question: "How would you design a notification system?", answer: "Components: Event Producer (triggers), Event Queue (Kafka/SQS), Notification Service (processes events), Template Engine, Delivery Services (Email/SMS/Push). User preferences store: which channels, quiet hours, frequency. Priority levels: urgent (real-time), normal (batched), low (digest). Retry with exponential backoff for failures. Rate limiting per user/channel. Analytics: delivery rates, open rates." },
    { question: "What is an API Gateway?", answer: "An API Gateway is a single entry point for all client requests. It handles: routing (directs to appropriate microservice), authentication/authorization, rate limiting, request/response transformation, load balancing, caching, SSL termination, logging/monitoring, circuit breaking. Examples: Kong, AWS API Gateway, Nginx. Prevents clients from knowing about internal service topology. Can also handle API versioning." },
    { question: "How would you design a file storage system like Google Drive?", answer: "Components: Upload Service (chunked uploads for large files), Metadata Service (file info, permissions, sharing in RDBMS), Block Storage Service (actual file chunks in distributed storage), Sync Service (detect changes, push updates to devices). Features: deduplication (hash each chunk), versioning, conflict resolution. Use CDN for downloads. Object storage (S3) for reliability. WebSocket/long-polling for real-time sync." },
    { question: "What is a load balancer and what are its types?", answer: "A load balancer distributes incoming traffic across multiple servers. Layer 4 (transport): routes based on IP/port, faster, no content inspection. Layer 7 (application): routes based on HTTP headers, URL path, cookies — more flexible. Algorithms: Round Robin, Weighted Round Robin, Least Connections, IP Hash, Least Response Time. Types: hardware (F5), software (Nginx, HAProxy), cloud (AWS ALB/NLB). Health checks remove unhealthy servers." },
    { question: "Explain the circuit breaker pattern.", answer: "Circuit breaker prevents cascading failures when a downstream service is unhealthy. States: Closed (normal — requests pass through), Open (service is down — fail fast without calling), Half-Open (test with limited requests to check recovery). When failure rate exceeds threshold → open circuit. After timeout → half-open. If test succeeds → close. Prevents resource exhaustion from waiting on failing services. Implementation: Hystrix, Resilience4j." },
    { question: "What is event-driven architecture?", answer: "Event-driven architecture uses events (state changes) to trigger and communicate between services. Components: Event Producers (emit events), Event Bus/Broker (Kafka, EventBridge), Event Consumers (react to events). Patterns: Event Notification (inform), Event-Carried State Transfer (include data in event), Event Sourcing (store all events as source of truth), CQRS (separate read/write models). Benefits: loose coupling, scalability, audit trail." },
    { question: "How would you design a search system like Elasticsearch?", answer: "Components: Data Ingestion Pipeline (collect and process documents), Indexer (build inverted index — maps terms to document IDs), Query Processor (parse query, retrieve matching documents), Ranker (score and sort results by relevance — TF-IDF, BM25). Distributed: shard index across nodes for parallel queries. Replicate shards for fault tolerance. Near-real-time indexing with refresh intervals. Autocomplete with prefix tries." },
    { question: "What is database replication and what are its types?", answer: "Replication copies data across multiple database instances for availability and read scaling. Master-Slave (single write node, multiple read replicas): simple but write bottleneck. Master-Master (multiple write nodes): higher availability but conflict resolution needed. Synchronous replication: consistent but slower (wait for all replicas). Asynchronous: faster but risk of data loss. Semi-synchronous: wait for at least one replica." },
    { question: "How would you design a web crawler?", answer: "Components: URL Frontier (priority queue of URLs to crawl), Fetcher (downloads pages — respect robots.txt, rate limiting), Parser (extract links and content), URL Deduplicator (bloom filter/hash set), Content Store (store crawled pages), DNS Resolver (cache for speed). Challenges: politeness (don't overload servers), trap detection (infinite loops), freshness (re-crawl frequency). Distributed crawling with coordination. BFS for broad crawls." },
    { question: "What is CQRS (Command Query Responsibility Segregation)?", answer: "CQRS separates read (Query) and write (Command) operations into different models/databases. Write model: optimized for consistency and business logic (normalized). Read model: optimized for query patterns (denormalized, materialized views). Benefits: independent scaling (more read replicas), optimized data models per use case, better performance. Often combined with Event Sourcing. Trade-off: eventual consistency between models, increased complexity." },
    { question: "Explain the concept of idempotency in API design.", answer: "An idempotent operation produces the same result regardless of how many times it's called. GET, PUT, DELETE are naturally idempotent. POST is not (creates duplicate resources). Why it matters: network retries may cause duplicate requests. Implementation: use idempotency keys (unique request ID stored server-side), check before processing. Payment APIs especially need idempotency to prevent double-charging." },
    { question: "How would you design a ride-sharing system like Uber?", answer: "Components: User Service, Driver Service, Trip Service, Matching Service (match riders with nearby drivers), Location Service (track driver positions in real-time using geospatial index — QuadTree/Geohash), Pricing Service (surge pricing based on demand), Payment Service, Notification Service. Real-time: WebSocket for driver tracking. Geospatial queries to find drivers within radius. ETA calculation using graph algorithms." },
  ],
  lld: [
    { question: "What are SOLID principles?", answer: "S — Single Responsibility: a class should have one reason to change. O — Open/Closed: open for extension, closed for modification. L — Liskov Substitution: subtypes must be substitutable for base types. I — Interface Segregation: prefer small, specific interfaces over large ones. D — Dependency Inversion: depend on abstractions, not concretions." },
    { question: "Design a parking lot system.", answer: "Classes: ParkingLot (floors, entry/exit points), ParkingFloor (spots list), ParkingSpot (type: compact/large/handicapped, isAvailable), Vehicle (type, licensePlate), Ticket (entryTime, spot, vehicle), Payment (amount, method). Patterns: Strategy for pricing, Factory for spot assignment. Use enums for VehicleType and SpotType. ParkingLot uses Singleton pattern." },
    { question: "Explain common design patterns with examples.", answer: "Creational: Singleton (DB connection), Factory (create objects without exposing logic), Builder (construct complex objects step-by-step). Structural: Adapter (convert interface), Decorator (add behavior dynamically), Facade (simplified interface). Behavioral: Observer (event handling), Strategy (interchangeable algorithms), Command (encapsulate requests)." },
    { question: "Design a library management system.", answer: "Classes: Library, Book (ISBN, title, author, copies), Member (id, name, membership), Librarian extends Member. BookItem (individual copy, rack location). BookLending (issueDate, dueDate, returnDate). Fine (amount, paid). Key methods: searchBook(), issueBook(), returnBook(), calculateFine(). Use Observer pattern to notify members when reserved book is available." },
    { question: "What is the difference between composition and inheritance?", answer: "Inheritance (IS-A): subclass extends superclass, inherits behavior. Tight coupling, changes in parent affect children. Composition (HAS-A): class contains instances of other classes. Loose coupling, more flexible, easier to test. Prefer composition over inheritance — it's more modular and avoids the fragile base class problem. Use inheritance only for true IS-A relationships." },
    { question: "Design an elevator system.", answer: "Classes: ElevatorSystem (manages multiple elevators), Elevator (currentFloor, direction, state), Request (floor, direction), Button (InternalButton, ExternalButton), Door. Use State pattern for elevator states (Moving, Idle, Stopped). Strategy pattern for scheduling algorithm (SCAN, LOOK, SSTF). Queue for pending requests. ElevatorSystem assigns requests to optimal elevator based on proximity and direction." },
    { question: "Explain the Singleton pattern and its pitfalls.", answer: "Singleton ensures only one instance of a class exists globally. Implementation: private constructor, static instance variable, static getInstance() method. Use cases: database connections, configuration, logging. Pitfalls: global state (makes testing hard), hidden dependencies, tight coupling, thread-safety issues in multi-threaded environments (use double-checked locking or static initialization). Often considered an anti-pattern — prefer dependency injection." },
    { question: "What is the Factory pattern? When would you use it?", answer: "Factory encapsulates object creation logic — the client requests an object without knowing the exact class. Simple Factory: a single method with switch/if logic. Factory Method: subclasses decide which class to instantiate. Abstract Factory: creates families of related objects. Use when: object creation is complex, you want to decouple creation from usage, or the exact type is determined at runtime (e.g., PaymentProcessor factory returning Stripe or PayPal)." },
    { question: "Explain the Observer pattern.", answer: "Observer defines a one-to-many dependency where when one object (subject) changes state, all dependents (observers) are notified. Components: Subject (maintains list of observers, notify()), Observer interface (update()), ConcreteObservers. Examples: event handlers, pub/sub systems, UI data binding, React state updates. Decouples the subject from its observers. Variants: push (subject sends data) vs pull (observers query subject)." },
    { question: "Design a Tic-Tac-Toe game.", answer: "Classes: Game (board, players, currentTurn, status), Board (3x3 grid, makeMove(), checkWinner()), Player (name, symbol X/O), Cell (row, col, symbol). Win detection: check rows, columns, diagonals after each move. Game states: IN_PROGRESS, X_WINS, O_WINS, DRAW. Use enum for CellState (EMPTY, X, O). Can extend to NxN board with configurable win length. Strategy pattern for AI player (random, minimax)." },
    { question: "What is the Strategy pattern?", answer: "Strategy defines a family of algorithms, encapsulates each one, and makes them interchangeable at runtime. Components: Context (uses a strategy), Strategy interface, ConcreteStrategies. Example: sorting algorithms (QuickSort, MergeSort), payment methods (CreditCard, PayPal, UPI), compression (ZIP, GZIP, RAR). Benefits: eliminates conditional statements, open/closed principle, easy to add new algorithms. Context delegates to strategy via interface." },
    { question: "Design an online bookstore like Amazon.", answer: "Classes: User (Account, Address), Book (ISBN, title, author, price, inventory), Cart (items, addItem(), total()), Order (items, status, payment, shipping), Payment (Strategy: CreditCard, UPI, Wallet), Shipping (Strategy: Standard, Express), Review (rating, comment). Patterns: Strategy for payment/shipping, Observer for order status notifications, Factory for creating orders, Repository for data access." },
    { question: "Explain the Builder pattern.", answer: "Builder separates the construction of a complex object from its representation, allowing the same construction process to create different representations. Components: Director (orchestrates), Builder interface (build steps), ConcreteBuilder (implements steps), Product (final object). Example: building a Pizza — setPizza(), addCheese(), addToppings(), addSauce() → build(). Fluent interface variant: return 'this' for method chaining." },
    { question: "What is the Decorator pattern?", answer: "Decorator dynamically adds responsibilities to an object without modifying its class. It wraps the original object with decorator objects that implement the same interface. Example: Coffee (base) → MilkDecorator → SugarDecorator → WhipCreamDecorator. Each decorator adds behavior and delegates to the wrapped object. Benefits: flexible alternative to subclassing, combine behaviors dynamically. Real-world: Java I/O streams, middleware chains." },
    { question: "Design a hotel booking system.", answer: "Classes: Hotel (rooms, amenities), Room (type, price, isAvailable), Reservation (guest, room, checkIn, checkOut, status), Guest (name, contact, bookings), Payment (amount, method, status). Key operations: searchAvailableRooms(dateRange, type), makeReservation(), cancelReservation(), checkIn(), checkOut(). Use State pattern for Room (Available, Booked, Occupied, Maintenance). Strategy for pricing (seasonal, dynamic). Observer for booking confirmations." },
    { question: "Explain the Adapter pattern.", answer: "Adapter converts the interface of a class into another interface that clients expect. It allows incompatible interfaces to work together. Types: Class Adapter (via inheritance), Object Adapter (via composition — preferred). Example: your code expects a MediaPlayer interface, but the library provides AdvancedMediaPlayer. Adapter wraps AdvancedMediaPlayer and implements MediaPlayer. Real-world: power socket adapters, API wrappers, legacy code integration." },
    { question: "What is the Command pattern?", answer: "Command encapsulates a request as an object, allowing parameterization, queuing, logging, and undo/redo operations. Components: Command interface (execute(), undo()), ConcreteCommand (receiver + action), Invoker (triggers commands), Receiver (performs the action). Example: text editor — TypeCommand, DeleteCommand, each with undo(). Supports macros (composite commands) and transaction-like behavior." },
    { question: "Design a movie ticket booking system like BookMyShow.", answer: "Classes: Movie (title, duration, genre), Cinema (halls, city), Hall (seats, screen), Show (movie, hall, time, availableSeats), Seat (row, number, type: Regular/Premium/VIP, status), Booking (user, show, seats, payment, status), User (name, email, bookings). Seat locking: temporary hold during booking (5 min timeout). Patterns: Strategy for pricing, State for seat status, Observer for notifications." },
    { question: "Explain the Facade pattern.", answer: "Facade provides a simplified, unified interface to a set of interfaces in a subsystem. It hides the complexity of the subsystem from the client. Example: a HomeTheaterFacade with watchMovie() that internally calls: projector.on(), screen.down(), dvdPlayer.play(), amplifier.setVolume(). Client doesn't need to know about individual components. Benefits: reduces coupling, simplifies usage. Doesn't prevent direct subsystem access if needed." },
    { question: "What is the State pattern?", answer: "State allows an object to alter its behavior when its internal state changes — the object appears to change its class. Components: Context (holds current state), State interface (methods for each behavior), ConcreteStates. Example: VendingMachine with states — HasCoin, NoCoin, Dispensing, SoldOut. Each state handles insertCoin(), selectProduct(), dispense() differently. Eliminates complex conditional logic (switch/if chains on state)." },
    { question: "Design a social media platform's post feature.", answer: "Classes: User (profile, followers, following), Post (author, content, media, timestamp, likes, comments, visibility), Comment (author, text, replies, likes), Like (user, target), Feed (posts sorted by time/relevance), Notification (type, sender, receiver). Patterns: Observer for notifications (new like/comment), Strategy for feed ranking, Iterator for paginated feed, Composite for nested comments." },
    { question: "What is dependency injection and why is it important?", answer: "Dependency injection provides objects their dependencies from outside rather than creating them internally. Types: Constructor injection (preferred — via constructor params), Setter injection (via setters), Interface injection. Benefits: loose coupling, easier testing (inject mocks), follows Dependency Inversion Principle. Example: instead of Service creating its own Database, receive Database via constructor. DI containers (Spring, Inversify) automate this." },
    { question: "Design a chess game.", answer: "Classes: Game (board, players, currentTurn, status, moveHistory), Board (8x8 grid of cells), Cell (position, piece), Piece (abstract: color, position, isValidMove()), King, Queen, Rook, Bishop, Knight, Pawn (each with movement rules), Player (color, pieces), Move (from, to, piece, captured). Special: castling, en passant, pawn promotion. Check detection: see if any opponent piece can reach the king. Checkmate: king in check with no valid moves." },
    { question: "Explain the Template Method pattern.", answer: "Template Method defines the skeleton of an algorithm in a base class, letting subclasses override specific steps without changing the algorithm's structure. The base class has a template method (final/non-overridable) that calls abstract/hook methods. Example: DataParser with parse() template: openFile() → readData() → processData() → closeFile(). CSVParser and JSONParser override readData() and processData(). Promotes code reuse while allowing customization." },
    { question: "What is the difference between abstract class and interface?", answer: "Abstract class: can have both abstract and concrete methods, constructor, instance variables, single inheritance only. Use for IS-A relationship with shared behavior. Interface: only method signatures (Java 8+ allows default methods), no constructor, no instance state, multiple implementation. Use for CAN-DO capability contracts. Prefer interfaces for loose coupling; abstract classes when sharing implementation among related classes." },
  ],
  aptitude: [
    { question: "A train 300m long passes a pole in 15 seconds. What is its speed?", answer: "Speed = Distance / Time = 300m / 15s = 20 m/s. Convert to km/h: 20 × (18/5) = 72 km/h. Key formula: To convert m/s to km/h, multiply by 18/5. When a train passes a pole, the distance covered equals the length of the train." },
    { question: "If A can do a job in 12 days and B can do it in 18 days, how long will they take together?", answer: "A's rate = 1/12 per day. B's rate = 1/18 per day. Combined rate = 1/12 + 1/18 = 3/36 + 2/36 = 5/36 per day. Time = 36/5 = 7.2 days. Formula: If A takes 'a' days and B takes 'b' days, together they take (a×b)/(a+b) days." },
    { question: "What is the probability of getting at least one head in 3 coin tosses?", answer: "P(at least one head) = 1 - P(no heads) = 1 - P(all tails) = 1 - (1/2)³ = 1 - 1/8 = 7/8. The complement approach is easier: instead of calculating P(1H) + P(2H) + P(3H), calculate 1 - P(0H). This works for any 'at least' probability problem." },
    { question: "A man invests Rs 10,000 at 10% compound interest for 2 years. Find the amount.", answer: "Formula: A = P(1 + R/100)^n = 10000(1 + 10/100)² = 10000 × (1.1)² = 10000 × 1.21 = Rs 12,100. Compound Interest = A - P = Rs 2,100. Simple Interest would be Rs 2,000. CI is always more than SI for n > 1 year." },
    { question: "In how many ways can 5 people be arranged in a row?", answer: "This is a permutation problem. n people in a row = n! = 5! = 5 × 4 × 3 × 2 × 1 = 120 ways. If arranged in a circle, it would be (n-1)! = 4! = 24 ways. If some are identical, divide by the factorial of the repeats." },
    { question: "Two pipes A and B can fill a tank in 20 and 30 minutes. A drain pipe C can empty it in 15 minutes. If all three are open, how long to fill?", answer: "A's rate = 1/20, B's rate = 1/30, C's rate = -1/15 (negative because it empties). Combined = 1/20 + 1/30 - 1/15 = 3/60 + 2/60 - 4/60 = 1/60 per minute. Time = 60 minutes. When the drain rate exceeds fill rate, the tank will never fill." },
    { question: "A boat goes 24 km upstream in 6 hours and 24 km downstream in 4 hours. Find the speed of the boat and stream.", answer: "Upstream speed = 24/6 = 4 km/h. Downstream speed = 24/4 = 6 km/h. Speed of boat in still water = (downstream + upstream)/2 = (6+4)/2 = 5 km/h. Speed of stream = (downstream - upstream)/2 = (6-4)/2 = 1 km/h." },
  ],
};

export function getQuestionsForSkill(skillName: string): InterviewQuestion[] {
  const lower = skillName.toLowerCase().trim();
  if (SKILL_QUESTIONS[lower]) return SKILL_QUESTIONS[lower];
  for (const [key, questions] of Object.entries(SKILL_QUESTIONS)) {
    if (lower.includes(key) || key.includes(lower)) return questions;
  }
  const words = lower.split(/[\s./\\-]+/);
  for (const word of words) {
    if (word.length > 2 && SKILL_QUESTIONS[word]) return SKILL_QUESTIONS[word];
  }
  return [];
}

export function shuffleArray<T>(array: T[]): T[] {
  const shuffled = [...array];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
}
